#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # Never break Claude Code on bad input

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input") or {}
    resp  = ev.get("tool_response") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    # Check for the specific interactive watcher command
    if command.strip().startswith("pnpm test") and "test:ci" not in command:
        # Use stderr for blocking message (exit code 2)
        print("REQUIRED FOLLOW-UP: Running `pnpm test` starts an interactive watcher and will time out. Use `pnpm test:ci` or `pnpm lint` instead. Do not stop until the correct command is used.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
import json, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0

    # Get the file path that was edited
    file_path = ev.get("tool_input", {}).get("file_path")
    if not file_path:
        return 0

    try:
        # Run ruff check on the modified file
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            check=False, # Do not raise exception on non-zero exit
            timeout=10
        )

        if result.returncode != 0 and result.stdout.strip() or result.stderr.strip():
            # Linting failed or warnings were found
            print("REQUIRED FOLLOW-UP: Code linting failed after edit. The following issues must be fixed before proceeding:", file=sys.stderr)
            print("----------------------------------------------------------------------------------", file=sys.stderr)
            print(result.stdout + result.stderr, file=sys.stderr)
            print("Fix all reported linting errors (e.g., indentation, formatting) and then summarize. Do not stop until clean.", file=sys.stderr)
            return 2 # Block/Signal failure

    except subprocess.CalledProcessError as e:
        # Handle subprocess execution errors
        print(f"BLOCKING: Failed to run ruff check on {file_path}. Error: {e.stderr}", file=sys.stderr)
        return 2
    except Exception as e:
        # Handle other unexpected errors
        print(f"BLOCKING: An unexpected error occurred during linting check: {e}", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for callers and feed the list back to Claude so it can verify consistency."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names: set[str] = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"BLOCKING: export `{name}` was edited. {len(hits)} stale references remain:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Fix each, then summarize. Do not stop. Do not ask.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block git push --force to main; require explicit confirmation for dangerous operations."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("tool_name") != "Bash":
        return 0

    cmd = (ev.get("tool_input") or {}).get("command", "")

    # Check for the dangerous pattern: force push to main
    if "git push --force" in cmd and "origin main" in cmd:
        print("REQUIRED FOLLOW-UP: Detected a force push to main. This is highly destructive and requires manual review. Please confirm this action is safe before proceeding.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

